import { useState, useMemo, useCallback, useEffect, useRef } from "react";
import { DEFAULT_FRANCHISOR, COMPANIES, COMPANY_NAMES, todayDmy, dmyToIso, isoToDmy } from "./data/franchisor";
import { StoreCtx } from "./lib/context";
import { fetchComps, fetchSaldos, appendComp, updateComp, removeComp,
         fetchFranchises, fetchFranchisor,
         sheetsSaveFr, sheetsAddFr, sheetsDeleteFr, sheetsSaveFranchisor,
         fetchRecordatorios, saveRecordatorio } from "./lib/sheetsApi";
import { CURRENCIES, MONTHS, AVAILABLE_YEARS, computeSaldo, computeSaldoPrevMes, downloadCSV } from "./lib/helpers";
import "./lib/styles";
import FrDetail from "./components/FrDetail";
import MaestrosModal from "./components/MaestrosModal";
import ImportBankModal from "./components/ImportBankModal";
import TabResumenMes from "./tabs/TabResumenMes";
import TabContabilidad from "./tabs/TabContabilidad";
import TabFacturador from "./tabs/TabFacturador";
import TabDeudores from "./tabs/TabDeudores";
import FrSearch from "./components/FrSearch";

const LOGO_SRC = "data:image/png;base64,";

// ─── ROOT APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [user,       setUser]      = useState({ name: "Admin" }); // login deshabilitado para testing
  const [showMaestros, setShowMaestros] = useState(false);
  const [showImport,   setShowImport]   = useState(false);
  const [franchisor,   setFranchisor]   = useState(null);
  const [tab,        setTab]       = useState("resumen");
  const [detailFilteredRows, setDetailFilteredRows] = useState([]);
  const [month,      setMonth]     = useState(() => new Date().getMonth());
  const [year,       setYear]      = useState(() => new Date().getFullYear());
  const [franchises, setFranchises]= useState([]);
  const [comps,          setComps]          = useState({});
  const compsRef = useRef({});
  compsRef.current = comps;
  const [saldoInicial,   setSaldoInicial]   = useState({});
  const [recordatorios,  setRecordatorios]  = useState({});
  const [sheetsReady,  setSheetsReady] = useState(false);
  const [loadError,    setLoadError]   = useState(null);
  const [modalFrId,  setModalFrId] = useState(null);   // null = closed, number = franchise id
  const [factState,  setFactState] = useState({       // Facturador state persists across tab switches
    stage: "idle", rows: [], editIdx: null, editBuf: {},
    processLog: [], loteId: `LOTE-${Date.now().toString(36).toUpperCase()}`
  });
  const [search,     setSearch]    = useState("");
  const [filterCur,  setFilterCur] = useState("ALL");
  const [cutoff,        setCutoff]        = useState(todayDmy);
  const [soloPendiente, setSoloPendiente] = useState(false);
  const [selectedFrIds, setSelectedFrIds] = useState(new Set());
  const [activeCompany, setActiveCompany] = useState(COMPANY_NAMES[0]); // default: "ÑAKO SRL"
  const [detailFilter, setDetailFilter] = useState("ALL");
  const [detailTipo,   setDetailTipo]   = useState(undefined);
  const [navCount,     setNavCount]     = useState(0);
  const [showAll,      setShowAll]      = useState(false);

  const saveFr = useCallback((id, data) => {
    setFranchises(prev => prev.map(f => f.id === id ? { ...f, ...data } : f));
    sheetsSaveFr(id, data).catch(err => console.error('Sheets saveFr:', err));
  }, []);

  const deleteFr = useCallback((id) => {
    setFranchises(prev => prev.filter(f => f.id !== id));
    setComps(prev => {
      const next = { ...prev };
      Object.keys(next).forEach(k => { if (k.startsWith(String(id) + "-")) delete next[k]; });
      return next;
    });
    sheetsDeleteFr(id).catch(err => console.error('Sheets deleteFr:', err));
  }, []);

  const addFr = useCallback((data) => {
    setFranchises(prev => {
      const maxId = Math.max(0, ...prev.map(f => f.id));
      const newFr = { ...data, id: maxId + 1 };
      sheetsAddFr(newFr).catch(err => console.error('Sheets addFr:', err));
      return [...prev, newFr];
    });
  }, []);

  const saveFranchisor = useCallback((side, data) => {
    setFranchisor(prev => ({ ...prev, [side]: { ...(prev?.[side] ?? {}), ...data } }));
    sheetsSaveFranchisor(side, data).catch(err => console.error('Sheets saveFranchisor:', err));
  }, []);

  const handleNavigate = useCallback((tab, filter, { tipo, cuenta, moneda } = {}) => {
    setTab(tab === "detalle" ? "contabilidad" : tab);
    if (filter) setDetailFilter(filter);
    // cuenta can be a string or array of strings
    setDetailTipo(cuenta ?? tipo ?? undefined);
    if (moneda) setFilterCur(moneda);
    setNavCount(n => n + 1);
  }, []);

  // O(1) franchise lookup — recomputed only when franchises list changes
  const franchiseMap = useMemo(
    () => new Map(franchises.map(f => [f.id, f])),
    [franchises]
  );

  const filteredFr = useMemo(() => {
    const q = search.toLowerCase().trim();
    return franchises.filter(f => {
      if (!q) return true;
      const name = f.name.toLowerCase();
      const exactMatch = franchises.some(x => x.name.toLowerCase() === q);
      return exactMatch ? name === q : name.startsWith(q) || name === q;
    });
  }, [franchises, search]);

  // Base para Resumen y Saldos: TODAS las sedes (activas e inactivas)
  // para que los saldos cierren correctamente
  const allActiveFr = useMemo(() => franchises, [franchises]);

  const activeFr = useMemo(() =>
    [...franchises].sort((a, b) => a.name.localeCompare(b.name, "es"))
  , [franchises]);

  // Stable mutation handlers — IDs are normalised to strings here, once
  const addComp = useCallback((frId, comp) => {
    const key = String(frId);
    setComps(prev => ({ ...prev, [key]: [...(prev[key] ?? []), comp] }));
    appendComp(frId, comp).catch(err => console.error('Sheets appendComp:', err));
  }, []);

  const delComp = useCallback((frId, compId) => {
    const key = String(frId);
    setComps(prev => ({ ...prev, [key]: (prev[key] ?? []).filter(c => c.id !== String(compId)) }));
    removeComp(frId, compId).catch(err => console.error('Sheets removeComp:', err));
  }, []);

  const editComp = useCallback((frId, compId, patch) => {
    const key = String(frId);
    setComps(prev => ({
      ...prev,
      [key]: (prev[key] ?? []).map(c => c.id === String(compId) ? { ...c, ...patch } : c),
    }));
    updateComp(frId, compId, patch).catch(err => console.error('Sheets updateComp:', err));
  }, []);

  const moveComp = useCallback((oldFrId, newFrId, compId, patch) => {
    const oldKey = String(oldFrId);
    const newKey = String(newFrId);
    const comp = (compsRef.current[oldKey] ?? []).find(c => c.id === String(compId));
    if (!comp) return;
    const updatedComp = { ...comp, ...patch, frId: newFrId };
    setComps(prev => ({
      ...prev,
      [oldKey]: (prev[oldKey] ?? []).filter(c => c.id !== String(compId)),
      [newKey]: [...(prev[newKey] ?? []), updatedComp],
    }));
    updateComp(oldFrId, compId, { ...patch, frId: String(newFrId) })
      .catch(err => {
        console.error('Sheets moveComp:', err);
        setComps(prev => ({
          ...prev,
          [oldKey]: [...(prev[oldKey] ?? []), comp],
          [newKey]: (prev[newKey] ?? []).filter(c => c.id !== String(compId)),
        }));
      });
  }, []);

  const handleExportCSV = useCallback(() => {
    if (tab === "contabilidad") {
      const rows = [["Fecha","Sede","Cuenta","Descripción","N° Comprobante","Debe","Haber","Saldo","Moneda"]];
      detailFilteredRows.forEach(r => {
        rows.push([
          r.displayDate ?? r.date ?? "",
          r.frName,
          r.tipoLabel ?? r.cuenta ?? "",
          r.concepto ?? "",
          r.invoice ?? "",
          r.debe > 0 ? r.debe.toFixed(2) : "",
          r.haber > 0 ? r.haber.toFixed(2) : "",
          r.saldo.toFixed(2),
          r.currency ?? "",
        ]);
      });
      downloadCSV(rows, `BIGG_Detalle_${MONTHS[month]}_${year}.csv`);
      return;
    }
    const rows = [["Franquicia","País","Moneda","Empresa","Saldo 31/12/2025","Devengado Mes","Saldo Final"]];
    filteredFr.forEach(fr => {
      const sp = computeSaldoPrevMes(fr.id, year, month, comps, saldoInicial, null, null, activeCompany);
      const sa = computeSaldo(fr.id, year, month, comps, saldoInicial, null, null, activeCompany);
      rows.push([fr.name, fr.country, fr.currency, activeCompany, sp.toFixed(2), (sa - sp).toFixed(2), sa.toFixed(2)]);
    });
    downloadCSV(rows, `BIGG_${MONTHS[month]}_${year}.csv`);
  }, [tab, detailFilteredRows, filteredFr, year, month, comps, saldoInicial]);

  // Context value — stable object ref changes only when relevant state changes
  const addRecordatorioEntry = useCallback((frId, entry) => {
    const key = String(frId);
    setRecordatorios(prev => ({ ...prev, [key]: [...(prev[key] ?? []), entry] }));
    saveRecordatorio({ frId, ...entry }).catch(err => console.error('Sheets recordatorio:', err));
  }, []);

  const storeValue = useMemo(
    () => ({ comps, saldoInicial, franchises, franchiseMap, editComp, moveComp, deleteComp: delComp, activeCompany, franchisor, recordatorios, addRecordatorioEntry }),
    [comps, saldoInicial, franchises, franchiseMap, editComp, moveComp, delComp, activeCompany, franchisor, recordatorios, addRecordatorioEntry]
  );

  const modalFr = modalFrId != null ? franchiseMap.get(modalFrId) : null;

  // if (!user) return <Login onLogin={setUser} />; // deshabilitado para testing

  // Cargar datos de Google Sheets al montar
  useEffect(() => {
    Promise.allSettled([fetchComps(), fetchSaldos(), fetchFranchises(), fetchFranchisor(), fetchRecordatorios()])
      .then(([compsRes, saldosRes, frRes, franchisorRes, recRes]) => {
        if (compsRes.status === 'fulfilled') setComps(compsRes.value);
        else { console.error('Sheets comps:', compsRes.reason); setLoadError(compsRes.reason.message); }

        if (saldosRes.status === 'fulfilled') setSaldoInicial(saldosRes.value);
        else console.error('Sheets saldos:', saldosRes.reason);

        if (frRes.status === 'fulfilled') setFranchises(frRes.value);
        else { console.error('Sheets franchises:', frRes.reason); }

        if (franchisorRes.status === 'fulfilled') setFranchisor(franchisorRes.value);
        else { console.warn('Sheets franchisor (fallback estático):', franchisorRes.reason); setFranchisor(DEFAULT_FRANCHISOR); }

        if (recRes.status === 'fulfilled') setRecordatorios(recRes.value ?? {});

        setSheetsReady(true);
      });
  }, []);

  if (!sheetsReady) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', background: 'var(--bg)', flexDirection: 'column', gap: 16 }}>
      <div style={{ width: 36, height: 36, border: '3px solid var(--border2)', borderTopColor: 'var(--accent)', borderRadius: '50%', animation: 'spin 0.8s linear infinite' }} />
      <div style={{ color: 'var(--muted)', fontSize: 13 }}>Cargando datos…</div>
    </div>
  );

  return (
    <StoreCtx.Provider value={storeValue}>
      {modalFr && (
        <FrDetail
          franchise={modalFr}
          month={month} year={year}
          onClose={() => setModalFrId(null)}
          onAddComp={addComp}
          onDelComp={delComp}
          onEditComp={editComp}
        />
      )}

      {showMaestros && (
        <MaestrosModal
          franchises={franchises}
          franchisor={franchisor}
          comps={comps}
          onSaveFr={saveFr}
          onAddFr={addFr}
          onDeleteFr={deleteFr}
          onSaveFranchisor={saveFranchisor}
          onClose={() => setShowMaestros(false)}
        />
      )}

      {showImport && (
        <ImportBankModal
          franchises={franchises}
          month={month}
          year={year}
          addComp={addComp}
          onClose={() => setShowImport(false)}
        />
      )}

      {/* HEADER */}
      <div style={{ background: "var(--bg2)", borderBottom: "2px solid var(--accent)", padding: "0 20px", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 20, height: 52, position: "sticky", top: 0, zIndex: 100 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <img src={LOGO_SRC} alt="BIGG" style={{ height: 34, width: "auto", maxWidth: 90, objectFit: "contain", flexShrink: 0, filter: "invert(1) sepia(1) saturate(10) hue-rotate(52deg)" }} />
          <div style={{ width: 1, height: 22, background: "var(--border2)" }} />
          <span style={{ color: "var(--muted)", fontSize: 12, fontWeight: 500, letterSpacing: ".05em" }}>Franquicias</span>
          <div style={{ display: "flex", gap: 5, alignItems: "center", marginLeft: 8 }}>
            {[["resumen","Resumen"],["saldos","Saldos"],["contabilidad","Detalle"]].map(([t, l]) => (
              <button key={t} className={`tab${tab === t ? " on" : ""}`} onClick={() => setTab(t)} style={{ minWidth: 80, textAlign: "center" }}>{l}</button>
            ))}
            <button
              onClick={() => setTab("facturador")}
              title="Nueva emisión"
              style={{
                width: 34, height: 34, borderRadius: "50%",
                border: "none",
                cursor: "pointer",
                background: tab === "facturador" ? "var(--accent)" : "rgba(173,255,25,.15)",
                color: tab === "facturador" ? "#1e2022" : "var(--accent)",
                fontSize: 22, fontWeight: 300, lineHeight: "1",
                display: "flex", alignItems: "center", justifyContent: "center",
                transition: "all .15s", marginLeft: 6, flexShrink: 0,
                boxShadow: tab === "facturador" ? "0 0 0 3px rgba(173,255,25,.35)" : "0 0 0 1px rgba(173,255,25,.3)",
              }}
            >+</button>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 10, flexShrink: 0 }}>
          {/* Selector de empresa franquiciante — cicla al siguiente con cada click */}
          <button
            style={{ padding: "4px 12px", fontSize: 12, background: "var(--bg)", border: "1px solid var(--border2)", color: "var(--text)", borderRadius: 6, fontFamily: "var(--font)", cursor: "pointer", fontWeight: 700, width: 160, textAlign: "left", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}
            onClick={() => {
              const cycle = [null, ...COMPANY_NAMES];
              const idx   = cycle.indexOf(activeCompany);
              const next  = cycle[(idx + 1) % cycle.length];
              setActiveCompany(next);
              setFilterCur(next ? (COMPANIES[next]?.currency ?? "ALL") : "ALL");
            }}
            title="Cambiar sociedad"
          >
            {activeCompany ? `${COMPANIES[activeCompany]?.flag} ${activeCompany}` : "Todas las soc."}
          </button>
          <button className="ghost" style={{ fontSize: 15, padding: "4px 8px" }} onClick={() => setShowMaestros(true)} title="Datos maestros">⚙</button>
          <div style={{ width: 1, height: 16, background: "var(--border2)" }} />
          <button className="ghost" style={{ fontSize: 10 }} onClick={() => setUser(null)}>Salir</button>
        </div>
      </div>
      {/* SUBBAR — una sola fila: Período + Moneda inline */}
      {tab !== "facturador" && tab !== "saldos" && (
      <div style={{ background: "var(--bg2)", borderBottom: "1px solid var(--border)", padding: "6px 20px", display: "flex", alignItems: "center", gap: 10, position: "sticky", top: 52, zIndex: 99 }}>
        {/* Período */}
        <span style={{ fontSize: 10, color: "var(--muted)", fontWeight: 700, letterSpacing: ".08em" }}>PERÍODO</span>
        <select style={{ padding: "4px 9px", fontSize: 12 }} value={month ?? new Date().getMonth()} onChange={e => { setMonth(parseInt(e.target.value)); setShowAll(false); }}>
          {MONTHS.map((m, i) => <option key={i} value={i}>{m}</option>)}
        </select>
        <select style={{ padding: "4px 9px", fontSize: 12 }} value={year} onChange={e => { setYear(parseInt(e.target.value)); setShowAll(false); }}>
          {AVAILABLE_YEARS.map(y => <option key={y} value={y}>{y}</option>)}
        </select>
        <button className="ghost" style={{ fontSize: 13, padding: "1px 5px" }} onClick={() => {
          if (month === 0) { setMonth(11); setYear(y => y - 1); } else { setMonth(m => m - 1); }
          setShowAll(false);
        }}>‹</button>
        <button className="ghost" style={{ fontSize: 13, padding: "1px 5px" }} onClick={() => {
          if (month === 11) { setMonth(0); setYear(y => y + 1); } else { setMonth(m => m + 1); }
          setShowAll(false);
        }}>›</button>
        {/* Historial completo — solo en Detalle */}
        {tab === "contabilidad" && (
          <button className={`tab${showAll ? " on" : ""}`} style={{ padding: "3px 11px", fontSize: 10 }} onClick={() => setShowAll(v => !v)}>Historial completo</button>
        )}
        {/* Moneda — solo en Detalle, inline a la derecha */}
        {tab === "contabilidad" && (<>
          <div style={{ width: 1, height: 16, background: "var(--border2)", marginLeft: 4 }} />
          <span style={{ fontSize: 10, color: "var(--muted)", fontWeight: 700, letterSpacing: ".08em" }}>MONEDA</span>
          {[["ALL","Todas"], ...CURRENCIES.map(c => [c, c])].map(([v, l]) => (
            <button key={v} className={`tab${filterCur === v ? " on" : ""}`} style={{ padding: "3px 12px", fontSize: 10 }} onClick={() => setFilterCur(v)}>{l}</button>
          ))}
        </>)}
        {tab === "resumen" && (
          <div style={{ marginLeft: "auto" }}>
            <FrSearch franchises={activeFr} selected={selectedFrIds} onChange={setSelectedFrIds} />
          </div>
        )}
        {tab === "contabilidad" && (
          <button className="ghost" style={{ fontSize: 10, marginLeft: "auto" }} onClick={handleExportCSV}>↓ CSV</button>
        )}
      </div>
      )}

      {/* Subbar deudores: fecha + pendiente + moneda */}
      {tab === "saldos" && (
        <div style={{ background: "var(--bg2)", borderBottom: "1px solid var(--border)", padding: "6px 20px", display: "flex", alignItems: "center", gap: 10, position: "sticky", top: 52, zIndex: 99 }}>
          <span style={{ fontSize: 10, color: "var(--muted)", fontWeight: 700, letterSpacing: ".08em" }}>AL</span>
          <input
            type="date"
            value={dmyToIso(cutoff)}
            onChange={e => setCutoff(isoToDmy(e.target.value))}
            style={{ padding: "4px 9px", fontSize: 12, background: "var(--bg)", border: "1px solid var(--border2)", color: "var(--text)", borderRadius: 6, fontFamily: "var(--font)", colorScheme: "dark" }}
          />
          <button
            className={`tab${soloPendiente ? " on" : ""}`}
            style={{ padding: "3px 12px", fontSize: 10 }}
            onClick={() => setSoloPendiente(v => !v)}
          >Saldo pendiente</button>
          <div style={{ width: 1, height: 16, background: "var(--border2)", marginLeft: 4 }} />
          <span style={{ fontSize: 10, color: "var(--muted)", fontWeight: 700, letterSpacing: ".08em" }}>MONEDA</span>
          {[["ALL","Todas"], ...CURRENCIES.map(c => [c, c])].map(([v, l]) => (
            <button key={v} className={`tab${filterCur === v ? " on" : ""}`} style={{ padding: "3px 12px", fontSize: 10 }} onClick={() => setFilterCur(v)}>{l}</button>
          ))}
          <div style={{ marginLeft: "auto" }}>
            <FrSearch franchises={activeFr} selected={selectedFrIds} onChange={setSelectedFrIds} />
          </div>
        </div>
      )}

      <div style={{ padding: "18px 20px", maxWidth: 1600 }}>
        {tab === "resumen"      && <TabResumenMes   allFranchises={allActiveFr} month={month} year={year} onNavigate={handleNavigate} selectedFrIds={selectedFrIds} />}
        {tab === "saldos"     && <TabDeudores     franchises={activeFr}    filterCur={filterCur} onOpenFr={setModalFrId} cutoff={cutoff} setCutoff={setCutoff} soloPendiente={soloPendiente} setSoloPendiente={setSoloPendiente} selectedFrIds={selectedFrIds} initialSection={detailFilter} />}
        {tab === "contabilidad" && <TabContabilidad key={`${detailFilter}-${detailTipo}-${navCount}`} franchises={filteredFr} month={month} year={year} onOpenFr={setModalFrId} initialFilter={detailFilter} initialTipo={detailTipo} showAll={showAll} multiCurrency={filterCur === "ALL"} filterCur={filterCur} onFilteredChange={setDetailFilteredRows} />}
        {tab === "facturador"   && <TabFacturador   month={month} year={year} onAddComp={addComp} factState={factState} setFactState={setFactState} franchisor={franchisor} onStartImport={() => setShowImport(true)} />}
      </div>
    </StoreCtx.Provider>
  );

}
